func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	query := `
		SELECT 
			u.display_name, 
			a.action_type, 
			COUNT(*) AS total_actions,
			SUM(CASE WHEN a.success THEN 1 ELSE 0 END) AS success_count,
			AVG(a.duration_ms) AS avg_duration
		FROM 
			user_activity a 
		JOIN 
			user_profile u ON a.user_id = u.id 
		WHERE 
			u.username IN (`

	for i := range usernames {
		if i > 0 {
			query += ","
		}
		query += "?"
	}
	query += ") AND a.created_at BETWEEN ? AND ?"

	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
	}

	query += " GROUP BY u.display_name, a.action_type"

	params := make([]interface{}, 0, len(usernames)+3)
	for _, uname := range usernames {
		params = append(params, uname)
	}
	params = append(params, startDate)
	params = append(params, endDate)
	if actionTypeFilter != "" {
		params = append(params, actionTypeFilter)
	}

	var summaries []UserActivitySummary
	_, err := o.Raw(query, params...).QueryRows(&summaries)
	if err != nil {
		return nil, err
	}
	return summaries, nil
}

func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	validFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !validFields[groupByField] {
		return nil, errors.New("invalid groupByField")
	}

	inClause := ""
	for i := range departments {
		if i > 0 {
			inClause += ","
		}
		inClause += "?"
	}

	query := fmt.Sprintf(`
		SELECT 
			%s AS group_value,
			COUNT(DISTINCT u.id) AS user_count,
			COUNT(a.id) AS total_activities
		FROM 
			user_profile u 
		LEFT JOIN 
			user_activity a ON u.id = a.user_id 
		WHERE 
			u.department IN (`+inClause+`)
		GROUP BY %s`, groupByField, groupByField)

	params := make([]interface{}, len(departments))
	for i, dept := range departments {
		params[i] = dept
	}

	var results []orm.Params
	_, err := o.Raw(query, params...).Values(&results)
	if err != nil {
		return nil, err
	}

	report := make([]map[string]interface{}, 0, len(results))
	for _, res := range results {
		entry := map[string]interface{}{
			"group_value":      res["group_value"],
			"user_count":       res["user_count"],
			"total_activities": res["total_activities"],
		}
		report = append(report, entry)
	}
	return report, nil
}

