		return []UserActivitySummary{}, nil
	}

	placeholders := make([]string, len(usernames))
	args := make([]interface{}, len(usernames))
	for i, username := range usernames {
		placeholders[i] = "?"
		args[i] = username
	}

	query := fmt.Sprintf(`
		SELECT u.display_name, a.action_type, 
			COUNT(*) as total_actions,
			SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count,
			AVG(a.duration_ms) as avg_duration
		FROM user_activity a 
		JOIN user_profile u ON a.user_id = u.id
		WHERE u.username IN (%s) 
			AND a.created_at BETWEEN ? AND ?`,
		strings.Join(placeholders, ","),
	)

	args = append(args, startDate)
	args = append(args, endDate)

	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
		args = append(args, actionTypeFilter)
	}

	query += " GROUP BY u.display_name, a.action_type"

	var summaries []UserActivitySummary
	_, err := o.Raw(query, args...).QueryRows(&summaries)
	if err != nil {
		return nil, err
	}

	return summaries, nil
}

func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	validFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !validFields[groupByField] {
		return nil, errors.New("invalid groupByField")
	}

	query := fmt.Sprintf(`
		SELECT 
			u.%s as group_value,
			COUNT(DISTINCT u.id) as user_count,
			COUNT(a.id) as total_activities
		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id`,
		groupByField,
	)

	args := []interface{}{}
	if len(departments) > 0 {
		placeholders := make([]string, len(departments))
		for i := range departments {
			placeholders[i] = "?"
			args = append(args, departments[i])
		}
		query += fmt.Sprintf(" WHERE u.department IN (%s)", strings.Join(placeholders, ","))
	}

	query += fmt.Sprintf(" GROUP BY u.%s", groupByField)

	var results []orm.Params
	_, err := o.Raw(query, args...).Values(&results)
	if err != nil {
		return nil, err
	}

	report := make([]map[string]interface{}, len(results))
	for i, row := range results {
		report[i] = map[string]interface{}{
			"group_value":      row["group_value"],
			"user_count":       row["user_count"],
			"total_activities": row["total_activities"],
		}
	}

	return report, nil
}

