func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	query := `
        SELECT 
            u.display_name, 
            a.action_type, 
            COUNT(*) as total, 
            SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, 
            AVG(a.duration_ms) as avg_duration
        FROM 
            user_activity a 
        JOIN 
            user_profile u ON a.user_id = u.id 
        WHERE 
            u.username IN (?) 
            AND a.created_at BETWEEN ? AND ?
    `

	if actionTypeFilter != "" {
		query += " AND a.action_type = ?"
	}

	query += " GROUP BY u.display_name, a.action_type"

	placeholders := make([]interface{}, 0, len(usernames)+3)
	placeholders = append(placeholders, strings.Join(usernames, ","))
	placeholders = append(placeholders, startDate)
	placeholders = append(placeholders, endDate)

	if actionTypeFilter != "" {
		placeholders = append(placeholders, actionTypeFilter)
	}

	var summaries []UserActivitySummary
	_, err := o.Raw(query, placeholders...).QueryRows(&summaries)
	if err != nil {
		return nil, err
	}

	return summaries, nil
}

func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	allowedFields := map[string]bool{
		"department":   true,
		"role":         true,
		"display_name": true,
	}
	if !allowedFields[groupByField] {
		return nil, errors.New("invalid groupByField")
	}

	query := `
        SELECT 
            u.%s AS group_value,
            COUNT(DISTINCT u.id) AS user_count,
            COUNT(a.id) AS total_activities
        FROM 
            user_profile u
        LEFT JOIN 
            user_activity a ON u.id = a.user_id
    `

	if len(departments) > 0 {
		query += " WHERE u.department IN ("
		placeholders := make([]string, len(departments))
		for i := range departments {
			placeholders[i] = "?"
		}
		query += strings.Join(placeholders, ",") + ")"
	}

	query += fmt.Sprintf(" GROUP BY u.%s", groupByField)

	params := make([]interface{}, 0, len(departments))
	for _, d := range departments {
		params = append(params, d)
	}

	var results []orm.Params
	_, err := o.Raw(fmt.Sprintf(query, groupByField), params...).Values(&results)
	if err != nil {
		return nil, err
	}

	// Convert []orm.Params to []map[string]interface{}
	converted := make([]map[string]interface{}, len(results))
	for i := range results {
		converted[i] = map[string]interface{}(results[i])
	}

	return converted, nil
}

