    "github.com/beego/beego/v2/client/orm"
)

type UserProfile struct {
    Id          int64     `orm:"column(id);pk;auto"`
    Username    string    `orm:"column(username);unique"`
    DisplayName string    `orm:"column(display_name)"`
    Email       string    `orm:"column(email)"`
    Department  string    `orm:"column(department)"`
    Role        string    `orm:"column(role)"`
    CreatedAt   time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivity struct {
    Id         int64     `orm:"column(id);pk;auto"`
    UserId     int64     `orm:"column(user_id)"`
    ActionType string    `orm:"column(action_type)"`
    Resource   string    `orm:"column(resource)"`
    IpAddress  string    `orm:"column(ip_address)"`
    Duration   int       `orm:"column(duration_ms)"`
    Success    bool      `orm:"column(success)"`
    CreatedAt  time.Time `orm:"column(created_at);auto_now_add"`
}

type UserActivitySummary struct {
    DisplayName  string
    ActionType   string
    TotalActions int
    SuccessCount int
    AvgDuration  float64
}

func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
    user := &UserProfile{
        Username:    username,
        DisplayName: displayName,
        Email:       email,
        Department:  department,
        Role:        role,
    }
    _, err := o.Insert(user)
    if err != nil {
        return nil, err
    }
    return user, nil
}

func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
    if len(usernames) == 0 {
        return []UserActivitySummary{}, nil
    }

    baseQuery := `
        SELECT 
            u.display_name AS display_name, 
            a.action_type AS action_type, 
            COUNT(*) AS total_actions,
            SUM(CASE WHEN a.success THEN 1 ELSE 0 END) AS success_count,
            AVG(a.duration_ms) AS avg_duration
        FROM user_activity a
        JOIN user_profile u ON a.user_id = u.id
        WHERE u.username IN (?` + repeatPlaceholders(len(usernames)-1) + `)
            AND a.created_at BETWEEN ? AND ?
    `
    if actionTypeFilter != "" {
        baseQuery += " AND a.action_type = ?"
    }
    baseQuery += " GROUP BY u.display_name, a.action_type"

    params := make([]interface{}, 0, len(usernames)+3)
    for _, u := range usernames {
        params = append(params, u)
    }
    params = append(params, startDate, endDate)
    if actionTypeFilter != "" {
        params = append(params, actionTypeFilter)
    }

    var summaries []UserActivitySummary
    _, err := o.Raw(baseQuery, params...).QueryRows(&summaries)
    if err != nil {
        return nil, err
    }
    return summaries, nil
}

func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
    allowedFields := map[string]bool{
        "department":    true,
        "role":          true,
        "display_name":  true,
    }
    if !allowedFields[groupByField] {
        return nil, errors.New("invalid groupByField")
    }

    baseQuery := `
        SELECT 
            u.` + groupByField + ` AS group_value,
            COUNT(DISTINCT u.id) AS user_count,
            COUNT(a.id) AS total_activities
        FROM user_profile u
        LEFT JOIN user_activity a ON u.id = a.user_id
    `
    if len(departments) > 0 {
        baseQuery += " WHERE u.department IN (?" + repeatPlaceholders(len(departments)-1) + ")"
    }
    baseQuery += " GROUP BY u." + groupByField

    var params []interface{}
    if len(departments) > 0 {
        for _, d := range departments {
            params = append(params, d)
        }
    }

    var results []orm.Params
    _, err := o.Raw(baseQuery, params...).Values(&results)
    if err != nil {
        return nil, err
    }

    report := make([]map[string]interface{}, len(results))
    for i, row := range results {
        report[i] = map[string]interface{}{
            "group_value":      row["group_value"],
            "user_count":       row["user_count"],
            "total_activities": row["total_activities"],
        }
    }
    return report, nil
}

func repeatPlaceholders(n int) string {
    if n <= 0 {
        return ""
    }
    s := ",?"
    return s + repeatPlaceholders(n-1)
}

